    public int lengthOfLIS(int[] nums) {
        // [Reader note] State setup
        // This setup stage creates the state needed for the invariant or partial result: Sequence-state reasoning, comparing current choices against prior history, and separating subsequences from substrings.
        if (nums.length == 1) return 1;

        int[] LIS = new int[nums.length];
        Arrays.fill(LIS, 1);
        int maximumSoFar = 1;

        // [Reader note] Main pass
        // This is the main sweep where the implementation earns its efficiency instead of restarting work from scratch.
        for (int i = nums.length - 1; i >= 0; i--) {
            for (int j = i + 1; j < nums.length; j++) {
                // [Reader note] Decision point
                // Pay attention here: The problem is conceptually clean, but the non-adjacent subsequence idea trips up many first reads.
                if (nums[i] < nums[j]) {
                    LIS[i] = Math.max(1 + LIS[j], LIS[i]);
                }
            }
            maximumSoFar = Math.max(maximumSoFar, LIS[i]);
        }
        return maximumSoFar;
    }

    // Binary search, O(nlogn)
    public int lengthOfLIS(int[] nums) {
        List<Integer> lis = new ArrayList<>(nums.length);

        for (int n : nums) {
            int i = Collections.binarySearch(lis, n);
            if (i < 0) i = -i - 1;

            if (i == lis.size())
                lis.add(n);
            else
                lis.set(i, n);
        }
        // [Reader note] Return
        // The final return exposes the result after the traversal and state updates have settled.
        return lis.size();
    }
}

