/*
// [Reader note] Entry point
// Start from the core routine and keep this mental model in view: Ask what the best increasing chain looks like if it must end at this position.
Given an integer array nums, return the length of the longest strictly increasing subsequence.
Time: O(nlog(n))
Space: O(n)
*/

int lengthOfLIS(int* nums, int numsSize){
    // [Reader note] State setup
    // This setup stage creates the state needed for the invariant or partial result: Sequence-state reasoning, comparing current choices against prior history, and separating subsequences from substrings.
    int max=0, mid, i, j;
    int* dp = calloc(numsSize, sizeof(int)); // dp[k] is the minimal last value of a subsequence of size k+1;
    dp[0] = nums[0];
    // [Reader note] Main pass
    // This is the main sweep where the implementation earns its efficiency instead of restarting work from scratch.
    for (int k=0; k<numsSize; k++) {
        i=0, j=max;
        while (i!=j) {
            mid = (i+j)/2;
            // [Reader note] Decision point
            // Pay attention here: The problem is conceptually clean, but the non-adjacent subsequence idea trips up many first reads.
            if (dp[mid]<nums[k])
                i=mid+1;
            else
                j=mid;
        }
        dp[i] = nums[k];
        if (i==max)
            max++;
    }
    free(dp);
    // [Reader note] Return
    // The final return exposes the result after the traversal and state updates have settled.
    return max;
}
